[14514]={"閃現術","75法力\n瞬發\n[q]將施法者傳送到正前方20碼的位置，路線上有阻擋物則會停止，傳送可以解除施法者身上一切形式的束縛。"},
[14515]={"統御意志","30法力 20 碼範圍\n2秒 施法時間"},
[14516]={"打擊","近戰範圍\n下一個近戰\n需要 近戰武器\n[q]攻擊一個敵人，對其造成額外的近戰傷害。"},
[14517]={"十字軍聖擊","40法力 近戰範圍\n瞬發\n需要 近戰武器\n[q]對目標造成27點傷害，每次十字軍聖擊都可使目標在受到神聖傷害時多承受10點額外神聖傷害，共可累加5次。持續30秒。"},
[14518]={"十字軍聖擊","40法力 近戰範圍\n瞬發\n需要 近戰武器\n[q]對目標造成50點傷害，每次十字軍聖擊都可使目標在受到神聖傷害時多承受20點額外神聖傷害，共可累加5次。持續30秒。"},
[14520]={"精神敏銳","[q]使你瞬發法術所消耗的法力降低2%。"},
[14521]={"冥想","[q]使你在施法時仍保持10%的法力恢復速度。"},
[14522]={"堅定意志","[q]使你抵抗昏迷、恐懼和沉默效果的機率額外提高3%。"},
[14523]={"無聲消退","[q]使你的神聖系和戒律系法術威脅值降低4%，同時使你的法術被驅散的機率降低4%。"},
[14524]={"魔杖專精","[q]使你魔杖造成的傷害提高5%。"},
[14525]={"魔杖專精","[q]使你魔杖造成的傷害提高10%。"},
[14526]={"魔杖專精","[q]使你魔杖造成的傷害提高15%。"},
