[14528]={"魔杖專精","[q]使你魔杖造成的傷害提高25%。"},
[14530]={"速度提升","瞬發\n[q]使你的奔跑速度提高40%，持續10秒。"},
[14531]={"殉難","[q]使你有50%的機率在受到敵人的近戰或遠程致命一擊後獲得專注施法的效果，持續6秒。專注施法的效果可防止因受到傷害而損失施放牧師法術的施法時間，並提高中斷效果的抗性10%。\n（特效觸發機率：50%）"},
[14532]={"慢性毒藥","2秒 施法時間\n[q]使附近敵人受到物理攻擊時所承受的傷害提高30%，持續5分鐘。"},
[14533]={"分離","瞬發\n[q]使附近敵人受到火焰、冰霜或秘法攻擊時承受的傷害提高50%，持續5分鐘。"},
[14534]={"倒鉤之刺","瞬發\n[q]使附近敵人的攻擊間隔時間延長54%，持續5分鐘。"},
[14535]={"病弱","瞬發\n[q]使附近敵人的所有屬性降低25%，持續5分鐘。"},
