[25022]={"萬鬼節驚駭"},
[25023]={"萬鬼節驚駭","（特效觸發機率：5%）"},
[25024]={"設置地雷","30法力 50 碼範圍\n瞬發 10秒 冷卻\n[q]裝置地雷。需花費3秒，一旦觸發造成2碼半徑內所有坦克35至45點傷害。"},
[25025]={"地震術","20 碼範圍\n瞬發\n[q]以震盪性的能量震擊敵人，並造成自然傷害，使其正在施放的法術被打斷，且在2秒內無法再次施放。"},
[25026]={"啟動MG砲塔","瞬發 10秒 冷卻\n[q]每秒10點法力。\n 每1秒對附近10碼內的敵人自動射擊，每次射擊造成2至4點傷害。"},
[25027]={"火焰噴射器","15 碼範圍\n瞬發 2秒 冷卻\n[q]每秒10點法力。\n 在面前5碼內的所有目標每1秒造成18至22點傷害。同時降低他們20%的移動速度並在每秒造成5點傷害，持續2秒。"},
